resource.manifest:
apiVersion: migrations.opensearch.org/v1alpha1
kind: TrafficReplay
metadata:
  name: "{{inputs.parameters.name}}"
  labels:
    workflows.argoproj.io/run-uid: "{{workflow.uid}}"
spec:
  jvmArgs: "{{=sprig.dig('jvmArgs', '', fromJSON(inputs.parameters.replayerOptions))}}"
  loggingConfigurationOverrideConfigMap: "{{=sprig.dig('loggingConfigurationOverrideConfigMap', '', fromJSON(inputs.parameters.replayerOptions))}}"
  podReplicas: {{=sprig.dig('podReplicas', 1, fromJSON(inputs.parameters.replayerOptions))}}
  resources: {{=fromJSON(inputs.parameters.replayerOptions)['resources']}}
  kafkaTrafficEnableMSKAuth: {{=sprig.dig('kafkaTrafficEnableMSKAuth', false, fromJSON(inputs.parameters.replayerOptions))}}
  kafkaTrafficPropertyFile: "{{=sprig.dig('kafkaTrafficPropertyFile', '', fromJSON(inputs.parameters.replayerOptions))}}"
  lookaheadTimeSeconds: {{=sprig.dig('lookaheadTimeSeconds', 400, fromJSON(inputs.parameters.replayerOptions))}}
  maxConcurrentRequests: {{=sprig.dig('maxConcurrentRequests', 10000, fromJSON(inputs.parameters.replayerOptions))}}
  numClientThreads: {{=sprig.dig('numClientThreads', 0, fromJSON(inputs.parameters.replayerOptions))}}
  observedPacketConnectionTimeout: {{=sprig.dig('observedPacketConnectionTimeout', 360, fromJSON(inputs.parameters.replayerOptions))}}
  otelCollectorEndpoint: "{{=sprig.dig('otelCollectorEndpoint', 'http://otel-collector:4317', fromJSON(inputs.parameters.replayerOptions))}}"
  quiescentPeriodMs: {{=sprig.dig('quiescentPeriodMs', 5000, fromJSON(inputs.parameters.replayerOptions))}}
  removeAuthHeader: {{=sprig.dig('removeAuthHeader', false, fromJSON(inputs.parameters.replayerOptions))}}
  speedupFactor: {{=sprig.dig('speedupFactor', 1.1, fromJSON(inputs.parameters.replayerOptions))}}
  targetServerResponseTimeoutSeconds: {{=sprig.dig('targetServerResponseTimeoutSeconds', 150, fromJSON(inputs.parameters.replayerOptions))}}
  transformerConfig: "{{=sprig.dig('transformerConfig', '', fromJSON(inputs.parameters.replayerOptions))}}"
  transformerConfigEncoded: "{{=sprig.dig('transformerConfigEncoded', '', fromJSON(inputs.parameters.replayerOptions))}}"
  transformerConfigFile: "{{=sprig.dig('transformerConfigFile', '', fromJSON(inputs.parameters.replayerOptions))}}"
  tupleTransformerConfig: "{{=sprig.dig('tupleTransformerConfig', '', fromJSON(inputs.parameters.replayerOptions))}}"
  tupleTransformerConfigBase64: "{{=sprig.dig('tupleTransformerConfigBase64', '', fromJSON(inputs.parameters.replayerOptions))}}"
  tupleTransformerConfigFile: "{{=sprig.dig('tupleTransformerConfigFile', '', fromJSON(inputs.parameters.replayerOptions))}}"
  userAgent: "{{=sprig.dig('userAgent', '', fromJSON(inputs.parameters.replayerOptions))}}"
